mapper.select:
SELECT
  session_id,
  event_id,
  event_type,
  emitted_at,
  data_json,
  error_json
FROM project_acp_session_events
WHERE project_id = #{project_id}
  AND session_id = #{session_id}
  AND (
    #{after_event_id, jdbcType=VARCHAR} IS NULL
    OR id > COALESCE(
      (
        SELECT id
        FROM project_acp_session_events
        WHERE project_id = #{project_id}
          AND session_id = #{session_id}
          AND event_id = #{after_event_id, jdbcType=VARCHAR}
        ORDER BY id DESC
        LIMIT 1
      ),
      0
    )
  )
ORDER BY id ASC
LIMIT #{size}
